#include <stdio.h>
#include <stdlib.h>
#define MAX_N 1000
#define MAX_Q 1000
// Define the structure for a tree node
typedef struct Node {
    int value;
    struct Node* left;
    struct Node* right;
} Node;
// Function to create a new node
Node* createNode(int value) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->value = value;
    newNode->left = newNode->right = NULL;
    return newNode;
}
// Function to insert a node into the tree
void insertNode(Node** root, int value) {
    if (*root == NULL) {
        *root = createNode(value);
    } else if (value < (*root)->value) {
        insertNode(&((*root)->left), value);
    } else if (value > (*root)->value) {
        insertNode(&((*root)->right), value);
    }
}
// Function to find the path between two nodes
void findPath(Node* root, int start, int finish, int* path, int* pathLength) {
    if (root == NULL) return;
    if (root->value == start || root->value == finish) {
        path[*pathLength] = root->value;
        (*pathLength)++;
    }
    findPath(root->left, start, finish, path, pathLength);
    findPath(root->right, start, finish, path, pathLength);
}
// Function to count the number of intersections with previous routes
int countIntersections(int* path, int pathLength, int** previousRoutes, int previousRoutesCount) {
    int intersections = 0;
    for (int i = 0; i < previousRoutesCount; i++) {
        for (int j = 0; j < pathLength; j++) {
            for (int k = 0; k < previousRoutes[i][1]; k++) {
                if (path[j] == previousRoutes[i][0][k]) {
                    intersections++;
                }
            }
        }
    }
    return intersections;
}
int main() {
    int N, Q;
    scanf("%d", &N);
    Node* root = NULL;
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        insertNode(&root, u);
        insertNode(&root, v);
    }
    scanf("%d", &Q);
    int** previousRoutes = (int**) malloc(Q * sizeof(int*));
    for (int i = 0; i < Q; i++) {
        previousRoutes[i] = (int*) malloc(2 * sizeof(int));
    }
    int previousRoutesCount = 0;
    for (int i = 0; i < Q; i++) {
        int start, finish;
        scanf("%d %d", &start, &finish);
        int* path = (int*) malloc(N * sizeof(int));
        int pathLength = 0;
        findPath(root, start, finish, path, &pathLength);
        previousRoutes[previousRoutesCount][0] = path;
        previousRoutes[previousRoutesCount][1] = pathLength;
        previousRoutesCount++;
        printf("%d\n", countIntersections(path, pathLength, previousRoutes, previousRoutesCount));
    }
    return 0;
}

