import java.util.ArrayList;
import java.util.Scanner;
public class Main {
    // Define the structure for a tree node
    static class Node {
        int value;
        Node left;
        Node right;
        Node(int value) {
            this.value = value;
            this.left = null;
            this.right = null;
        }
    }
    // Function to create a new node
    static Node createNode(int value) {
        return new Node(value);
    }
    // Function to insert a node into the tree
    static void insertNode(Node root, int value) {
        if (root == null) {
            root = createNode(value);
        } else if (value < root.value) {
            if (root.left == null) {
                root.left = createNode(value);
            } else {
                insertNode(root.left, value);
            }
        } else if (value > root.value) {
            if (root.right == null) {
                root.right = createNode(value);
            } else {
                insertNode(root.right, value);
            }
        }
    }
    // Function to find the path between two nodes
    static void findPath(Node root, int start, int finish, ArrayList<Integer> path) {
        if (root == null) return;
        if (root.value == start || root.value == finish) {
            path.add(root.value);
        }
        findPath(root.left, start, finish, path);
        findPath(root.right, start, finish, path);
    }
    // Function to count the number of intersections with previous routes
    static int countIntersections(ArrayList<Integer> path, ArrayList<ArrayList<Integer>> previousRoutes) {
        int intersections = 0;
        for (int i = 0; i < previousRoutes.size(); i++) {
            for (int j = 0; j < path.size(); j++) {
                for (int k = 0; k < previousRoutes.get(i).size(); k++) {
                    if (path.get(j).equals(previousRoutes.get(i).get(k))) {
                        intersections++;
                    }
                }
            }
        }
        return intersections;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        Node root = null;
        for (int i = 0; i < N - 1; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            insertNode(root, u);
            insertNode(root, v);
        }
        int Q = scanner.nextInt();
        ArrayList<ArrayList<Integer>> previousRoutes = new ArrayList<>();
        for (int i = 0; i < Q; i++) {
            int start = scanner.nextInt();
            int finish = scanner.nextInt();
            ArrayList<Integer> path = new ArrayList<>();
            findPath(root, start, finish, path);
            previousRoutes.add(path);
            System.out.println(countIntersections(path, previousRoutes));
        }
    }
}

